  const paint = Skia.Paint();
  paint.setColor(Skia.Color('#FFD700')); // Yellow
  canvas.drawRect({ x: 0, y: height - barH, width, height: barH }, paint);

  // Black stripes
  paint.setColor(Skia.Color('black'));
  const stripeW = 40 * scale;
  for (let i = -10; i < width / stripeW + 10; i++) {
     const path = Skia.Path.Make();
     const x = i * stripeW * 2;
     path.moveTo(x, height - barH);
     path.lineTo(x + stripeW, height - barH);
     path.lineTo(x - (barH/2), height);
     path.lineTo(x - (barH/2) - stripeW, height);
     path.close();
     canvas.drawPath(path, paint);
  }

  // White Box for Info
  paint.setColor(Skia.Color('white'));
  const boxW = width * 0.8;
  const boxH = 160 * scale;
  canvas.drawRect({ x: (width-boxW)/2, y: height - barH - (boxH/2), width: boxW, height: boxH }, paint);

  // Text
  paint.setColor(Skia.Color('black'));
  const titleFont = condensed;
  titleFont.setSize(45 * scale);
  drawTextCentered(canvas, name.toUpperCase(), height - barH - 10*scale, titleFont, paint, width);

  const phFont = bold;
  phFont.setSize(35 * scale);
